import json

lines = open('ios_crash.ips').readlines()
crash = json.loads(''.join(lines[1:]))

# Check for termination info
for key in ['termination','crashReporterKey','exception','vmRegionInfo','extMods','coalitionName','procRole']:
    if key in crash:
        print(f'{key}: {crash[key]}')

# Check for any extra info in threads
threads = crash.get('threads',[])
for i, t in enumerate(threads):
    for key in ['triggered','threadState']:
        if key in t and key == 'triggered':
            print(f'Thread {i} triggered: {t[key]}')
